<?php
namespace App\Services\ValidasiAhli;
use App\Models\{ExpertValidationAssessment,ExpertValidationInvitation,ExpertValidationInstrument};use App\Services\Audit\AuditLogger;use Illuminate\Http\Request;
class ExpertValidationService { public function createInvitation(ExpertValidationInstrument $instrument, ?int $validatorUserId, string $token, \DateTimeInterface $expiresAt): ExpertValidationInvitation { return ExpertValidationInvitation::query()->create(['instrument_id'=>$instrument->id,'validator_user_id'=>$validatorUserId,'invite_token'=>$token,'expires_at'=>$expiresAt]); } public function saveDraft(ExpertValidationInstrument $instrument, int $validatorId, array $data): ExpertValidationAssessment { $assessment=ExpertValidationAssessment::query()->firstOrCreate(['instrument_id'=>$instrument->id,'validator_user_id'=>$validatorId],['status'=>'draft']); abort_if(in_array($assessment->status,['submitted','locked'],true),422,'Hasil sudah dikunci'); $assessment->update(['score'=>$data['score'] ?? $assessment->score,'notes'=>$data['notes'] ?? $assessment->notes,'status'=>'draft']); return $assessment->fresh(); } public function submitFinal(ExpertValidationInstrument $instrument, int $validatorId, AuditLogger $audit, Request $request): ExpertValidationAssessment { $assessment=ExpertValidationAssessment::query()->firstOrCreate(['instrument_id'=>$instrument->id,'validator_user_id'=>$validatorId],['status'=>'draft']); abort_if(in_array($assessment->status,['submitted','locked'],true),422,'Submit final sudah dikunci'); $before=$assessment->toArray(); $assessment->update(['status'=>'locked','submitted_at'=>now(),'locked_at'=>now()]); $audit->log('expert.validation.submit_final_lock',$request,'expert_validation_assessments',$assessment->id,$before,$assessment->fresh()->toArray()); return $assessment->fresh(); } public function recap(): array { return ExpertValidationAssessment::query()->selectRaw('instrument_id,status,COUNT(*) total,AVG(score) avg_score')->groupBy('instrument_id','status')->get()->toArray(); }}
